valueSchema:
{
  "$schema": "http://json-schema.org/draft-04/schema#",
  "type": "object",
  "properties": {
    "preferredLanguage": {
      "type": "string",
      "displayName": "Preferred Language",
      "description": "The user's preferred written or spoken languages, which are optional. This may be explicitly set to null when updating a user to unset it. If provided, the format of the value is the same as the HTTP Accept-Language header field (not including \"Accept-Language:\") and is specified in Section 5.3.5 of RFC 7231.",
      "schemaType": "STANDARD"
    },
    "timezone": {
      "type": "string",
      "displayName": "Timezone",
      "description": "The user's time zone, which is optional. This may be explicitly set to null when updating a user to unset it. If provided, it must conform with the IANA Time Zone database format [RFC6557], also known as the \"Olson\" time zone database format [Olson-TZ] (e.g., \"America/Los_Angeles\")",
      "schemaType": "STANDARD"
    },
    "lastSignOn": {
      "type": "object",
      "displayName": "Last Sign-on",
      "description": "Last Sign-on Information",
      "schemaType": "CORE",
      "properties": {
        "at": {
          "type": "string",
          "displayName": "Last Sign-on Time",
          "description": "The time of the last successful login of the user via the Flow API.",
          "schemaType": "CORE"
        },
        "remoteIp": {
          "type": "string",
          "displayName": "Last Sign-on Remote IP",
          "description": "The IP address of the last successful login of the user via the Flow API.",
          "schemaType": "CORE"
        }
      }
    },
    "title": {
      "type": "string",
      "displayName": "Title",
      "description": "The user's title, which is optional, such as \"Vice President\". This may be explicitly set to null when updating a user to unset it.",
      "schemaType": "STANDARD"
    },
    "type": {
      "type": "string",
      "displayName": "Type",
      "description": "The user's type, which is optional. This may be explicitly set to null when updating a user to unset it. This attribute is organization-specific and has no special meaning within the platform. It could have values of \"Contractor\", \"Employee\", \"Intern\", \"Temp\", \"External\", and \"Unknown\"",
      "schemaType": "STANDARD"
    },
    "locale": {
      "type": "string",
      "displayName": "Locale",
      "description": "The user's default location, which is optional. This may be explicitly set to null when updating a user to unset it. This is used for purposes of localizing such items as currency, date time format, or numerical representations. If provided, a valid value is a language tag as defined in RFC 5646. The following are example tags: fr, en-US, es-419, az-Arab, x-pig-latin, man-Nkoo-GN",
      "schemaType": "STANDARD"
    },
    "enabled": {
      "type": "boolean",
      "displayName": "Enabled",
      "description": "A read-only attribute that specifies whether the user is enabled. This attribute is set to 'true' by default when the user is created.",
      "schemaType": "CORE"
    },
    "identityProvider": {
      "type": "object",
      "displayName": "Identity Provider",
      "description": "A read-only attribute that contains information about the user's trusted identity provider.",
      "schemaType": "CORE",
      "properties": {
        "id": {
          "type": "string",
          "displayName": "Identity Provider ID",
          "description": "An attribute containing the ID of the identity provider that is used as the authentication authority for the user. If present, the user must authenticate via this identity provider.",
          "schemaType": "CORE"
        },
        "type": {
          "type": "string",
          "displayName": "Identity Provider Type",
          "description": "A read-only attribute containing the type of the identity provider where the user account is managed. If the type is PING_ONE, PingOne is the authentication authority.",
          "schemaType": "CORE"
        }
      }
    },
    "lifecycle": {
      "type": "object",
      "displayName": "lifecycle",
      "description": "The account lifecycle",
      "schemaType": "CORE",
      "properties": {
        "status": {
          "type": "string",
          "displayName": "Status",
          "description": "The lifecycle status for this account.",
          "schemaType": "CORE"
        }
      }
    },
    "createdAt": {
      "type": "string",
      "displayName": "Creation Time",
      "description": "A read-only attribute that specifies the time at which the user was created.",
      "schemaType": "CORE"
    },
    "verifyStatus": {
      "type": "string",
      "displayName": "ID Validation Verification Authentication Enabled",
      "description": "A read-only attribute that specifies whether ID Validation authentication is enabled. This attribute is set to 'NOT-INITIATED' by default when the user is created.",
      "schemaType": "CORE"
    },
    "nickname": {
      "type": "string",
      "displayName": "Nickname",
      "description": "The user's nickname, which is optional. This may be explicitly set to null when updating a user to unset it. Valid characters consists of any Unicode letter, mark (e.g. accent, umlaut), math symbol, numeric character, or punctuation. It may have a length of no more than 256 characters.",
      "schemaType": "STANDARD"
    },
    "mfaEnabled": {
      "type": "boolean",
      "displayName": "Multi-factor Authentication Enabled",
      "description": "A read-only attribute that specifies whether multi-factor authentication is enabled. This attribute is set to 'false' by default when the user is created.",
      "schemaType": "CORE"
    },
    "id": {
      "type": "string",
      "displayName": "User ID",
      "description": "The globally unique identifier of the user.",
      "schemaType": "CORE"
    },
    "email": {
      "type": "string",
      "displayName": "Email Address",
      "description": "The user's email address",
      "schemaType": "STANDARD"
    },
    "updatedAt": {
      "type": "string",
      "displayName": "Last Modified Time",
      "description": "A read-only attribute that specifies the time at which the user was last modified.",
      "schemaType": "CORE"
    },
    "address": {
      "type": "object",
      "displayName": "Address",
      "description": "The user's address (optional)",
      "schemaType": "STANDARD",
      "properties": {
        "streetAddress": {
          "type": "string",
          "displayName": "Street Address",
          "description": "The full street address component, which may include house number, street name, P.O. box, and multi-line extended street address information. This attribute may contain newlines.",
          "schemaType": "STANDARD"
        },
        "locality": {
          "type": "string",
          "displayName": "Locality",
          "description": "The city or locality component of the address.",
          "schemaType": "STANDARD"
        },
        "region": {
          "type": "string",
          "displayName": "Region",
          "description": "The state or region component of the address.",
          "schemaType": "STANDARD"
        },
        "postalCode": {
          "type": "string",
          "displayName": "Postal Code",
          "description": "The zip code or postal code component of the address.",
          "schemaType": "STANDARD"
        },
        "countryCode": {
          "type": "string",
          "displayName": "Country Code",
          "description": "The country name component. When specified, the value MUST be in ISO 3166-1 \"alpha-2\" code format [ISO3166]; e.g., the United States and Sweden are \"US\" and \"SE\", respectively.",
          "schemaType": "STANDARD"
        }
      }
    },
    "externalId": {
      "type": "string",
      "displayName": "External ID",
      "description": "An identifier for the user resource as defined by the provisioning client. This is optional. This may be explicitly set to null when updating a user to unset it. The externalId attribute may simplify the correlation of the user in PingOne with the user's account in another system of record. The platform does not use this attribute directly in any way, but it is used by Ping Identity's Data Sync product.",
      "schemaType": "STANDARD"
    },
    "photo": {
      "type": "object",
      "displayName": "Photo",
      "description": "The user's photo URL (optional)",
      "schemaType": "STANDARD",
      "properties": {
        "href": {
          "type": "string",
          "displayName": "Photos Link",
          "description": "A URI that is a uniform resource locator (as defined in Section 1.1.3 of RFC 3986) that points to a resource location representing the user's image. This may be removed from a user by setting the photo attribute to null. If provided, the resource must be a file (e.g., a GIF, JPEG, or PNG image file) rather than a web page containing an image. It must also have a scheme of http or https.",
          "schemaType": "STANDARD"
        }
      }
    },
    "population": {
      "type": "object",
      "displayName": "Population",
      "description": "The name of the population in which the user’s identity exists.",
      "schemaType": "CORE",
      "properties": {
        "id": {
          "type": "sring",
          "displayName": "Population ID",
          "description": "The unique identifier for the population in which the user’s identity exists.",
          "schemaType": "CORE"
        }
      }
    },
    "primaryPhone": {
      "type": "string",
      "displayName": "Primary Phone",
      "description": "The user's primary phone number, which is optional. This might also match the mobilePhone attribute. This may be explicitly set to null when updating a user to unset it. If provided, it must consist of at least one digit and must not contain more than 32 characters.",
      "schemaType": "STANDARD"
    },
    "accountId": {
      "type": "string",
      "displayName": "Account ID",
      "description": "The user's account ID, which is optional. This may be explicitly set to null when updating a user to unset it. This attribute is organization-specific and has no special meaning within the platform.",
      "schemaType": "STANDARD"
    },
    "emailVerified": {
      "type": "boolean",
      "displayName": "Email Verified",
      "description": "A read-only attribute that specifies whether the email is verified.",
      "schemaType": "CORE"
    },
    "mobilePhone": {
      "type": "string",
      "displayName": "Mobile Phone",
      "description": "The user's mobile phone number, which is optional. This might also match the primaryPhone attribute. This may be explicitly set to null when updating a user to unset it. If provided, it must consist of at least one digit and must not contain more than 32 characters.",
      "schemaType": "STANDARD"
    },
    "name": {
      "type": "object",
      "displayName": "Name",
      "description": "The user's name (optional)",
      "schemaType": "STANDARD",
      "properties": {
        "formatted": {
          "type": "string",
          "displayName": "Formatted",
          "description": "The fully formatted name of the User (for example 'Ms. Barbara J Jensen, III'). This may be explicitly set to null when updating a name to unset it.",
          "schemaType": "STANDARD"
        },
        "given": {
          "type": "string",
          "displayName": "Given Name",
          "description": "The given name of the User, or First in most Western languages (for example, 'Barbara' given the full name 'Ms. Barbara J Jensen, III'). This may be explicitly set to null when updating a name to unset it. Valid characters consists of any Unicode letter, mark (e.g. accent, umlaut), math symbol, numeric character, or punctuation. It may have a length of no more than 256 characters.",
          "schemaType": "STANDARD"
        },
        "middle": {
          "type": "string",
          "displayName": "Middle Name",
          "description": "The the middle name(s) of the User (e.g., 'Jane' given the full name 'Ms. Barbara Jane Jensen, III'). This may be explicitly set to null when updating a name to unset it. Valid characters consists of any Unicode letter, mark (e.g. accent, umlaut), math symbol, numeric character, or punctuation. It may have a length of no more than 256 characters.",
          "schemaType": "STANDARD"
        },
        "family": {
          "type": "string",
          "displayName": "Family Name",
          "description": "The family name of the User, or Last in most Western languages (for example, 'Jensen' given the full name 'Ms. Barbara J Jensen, III'). This may be explicitly set to null when updating a name to unset it. Valid characters consists of any Unicode letter, mark (e.g. accent, umlaut), math symbol, numeric character, or punctuation. It may have a length of no more than 256 characters.",
          "schemaType": "STANDARD"
        },
        "honorificPrefix": {
          "type": "string",
          "displayName": "Honorific Prefix",
          "description": "The honorific prefix(es) of the User, or title in most Western languages (e.g., 'Ms.' given the full name 'Ms. Barbara Jane Jensen, III'). This may be explicitly set to null when updating a name to unset it.",
          "schemaType": "STANDARD"
        },
        "honorificSuffix": {
          "type": "string",
          "displayName": "Honorific Suffix",
          "description": "The honorific suffix(es) of the User, or suffix in most Western languages (e.g., 'III' given the full name 'Ms. Barbara Jane Jensen, III'). This may be explicitly set to null when updating a name to unset it.",
          "schemaType": "STANDARD"
        }
      }
    },
    "account": {
      "type": "object",
      "displayName": "Account",
      "description": "A read-only attribute that contains information about the user's account",
      "schemaType": "CORE",
      "properties": {
        "canAuthenticate": {
          "type": "boolean",
          "displayName": "Can Authenticate",
          "description": "A read-only attribute that specifies whether the user can authenticate at this time.",
          "schemaType": "CORE"
        },
        "status": {
          "type": "string",
          "displayName": "Account Status",
          "description": "A read-only attribute that specifies the status of the account.",
          "schemaType": "CORE"
        },
        "lockedAt": {
          "type": "string",
          "displayName": "Locked Time",
          "description": "A read-only attribute that specifies the time at which the account was locked, if any.",
          "schemaType": "CORE"
        },
        "secondsUntilUnlock": {
          "type": "string",
          "displayName": "Seconds Until Unlock",
          "description": "A read-only attribute that specifies the number of seconds remaining until the account will be unlocked.",
          "schemaType": "CORE"
        },
        "unlockAt": {
          "type": "string",
          "displayName": "Unlock Time",
          "description": "A read-only attribute that specifies the time at which the account will be unlocked.",
          "schemaType": "CORE"
        }
      }
    },
    "username": {
      "type": "string",
      "displayName": "Username",
      "description": "The username, which must be provided and must be unique within an environment. The username must be a string of any Unicode letter, mark (e.g. accent, umlaut), math symbol, numeric character, or punctuation. It may have a length of no more than 128 characters.",
      "schemaType": "CORE"
    },
    "department": {
      "type": "string",
      "displayName": "Department",
      "schemaType": "CUSTOM"
    },
    "jobTitle": {
      "type": "string",
      "displayName": "Job Title",
      "schemaType": "CUSTOM"
    },
    "advisorAttributes": {
      "type": "object",
      "displayName": "Advisor Attributes",
      "schemaType": "CUSTOM"
    }
  }
}

